import React from 'react';
import IconButton from '@material-ui/core/IconButton';
import DeleteIcon from '@material-ui/icons/Delete';

function ImageUpload({ imagePreviews, handleImageChange, handleRemoveImage, existingImage }) {

  useEffect(() => {
    console.log("exist: ", existingImage)
  }, [])
  return (
    <div>
      <input
        type="file"
        name="images"
        accept="image/*"
        onChange={handleImageChange}
        multiple
      />
      {/* Loopa igenom befintliga bilder och rendera dem */}
      {existingImage && (
        <div>
          <img
            src={`https://nice-special-meadow.glitch.me/images/${existingImage}`}
            alt={`Existing Image`}
            style={{ maxWidth: '100px', maxHeight: '100px' }}
          />
          <IconButton onClick={handleRemoveImage}>
            <DeleteIcon />
          </IconButton>
        </div>
      )}
      {/* Loopa igenom bildförhandsvisningar och rendera dem */}
      {imagePreviews.map((preview, index) => (
        <div key={index}>
          <img
            src={preview}
            alt={`Preview ${index + 1}`}
            style={{ maxWidth: '100px', maxHeight: '100px' }}
          />
          <IconButton onClick={() => handleRemoveImage(index)}>
            <DeleteIcon />
          </IconButton>
        </div>
      ))}
    </div>
  );
}

export default ImageUpload;
